-- SQL Setup for Call Center Application (Clean Installation)
-- Database name: createso_datosVPS
-- Table Prefix: biartet_

CREATE TABLE IF NOT EXISTS `biartet_grupos` (
  `id` INT AUTO_INCREMENT PRIMARY KEY,
  `nombre` VARCHAR(100) NOT NULL,
  `fecha_creacion` DATETIME NOT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS `biartet_users` (
  `id` INT AUTO_INCREMENT PRIMARY KEY,
  `username` VARCHAR(100) NOT NULL UNIQUE,
  `password` VARCHAR(255) NOT NULL,
  `is_admin` TINYINT(1) DEFAULT 0,
  `nombre_completo` VARCHAR(255) NULL,
  `usuario_dialview` VARCHAR(100) NULL,
  `contrasena_dialview` VARCHAR(255) NULL,
  `fecha_eliminacion` DATETIME NULL,
  `grupo_id` INT NULL,
  `fecha_creacion` DATETIME NOT NULL,
  `fecha_actualizacion` DATETIME NOT NULL,
  FOREIGN KEY (`grupo_id`) REFERENCES `biartet_grupos`(`id`) ON DELETE SET NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS `biartet_productos` (
  `id` INT AUTO_INCREMENT PRIMARY KEY,
  `nombre` VARCHAR(255) NOT NULL,
  `descripcion` TEXT,
  `imagen` VARCHAR(255) NULL,
  `precio_moneda_local` DECIMAL(10,2) NOT NULL DEFAULT 0.00,
  `usuario_id` INT NULL,
  `grupo_id` INT NULL,
  `fecha_creacion` DATETIME NOT NULL,
  `fecha_actualizacion` DATETIME NOT NULL,
  FOREIGN KEY (`usuario_id`) REFERENCES `biartet_users`(`id`) ON DELETE CASCADE,
  FOREIGN KEY (`grupo_id`) REFERENCES `biartet_grupos`(`id`) ON DELETE SET NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS `biartet_campanas` (
  `id` INT AUTO_INCREMENT PRIMARY KEY,
  `nombre` VARCHAR(255) NOT NULL,
  `charla_saludo` VARCHAR(2000) NOT NULL,
  `charla_desarrollo` TEXT NOT NULL,
  `charla_cierre` TEXT NOT NULL,
  `estado` TINYINT DEFAULT 1,
  `usuario_id` INT NULL,
  `grupo_id` INT NULL,
  `fecha_creacion` DATETIME NOT NULL,
  `fecha_actualizacion` DATETIME NOT NULL,
  FOREIGN KEY (`usuario_id`) REFERENCES `biartet_users`(`id`) ON DELETE CASCADE,
  FOREIGN KEY (`grupo_id`) REFERENCES `biartet_grupos`(`id`) ON DELETE SET NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS `biartet_campana_items` (
  `id` INT AUTO_INCREMENT PRIMARY KEY,
  `campana_id` INT NOT NULL,
  `producto_id` INT NOT NULL,
  `nombre_producto` VARCHAR(255) NOT NULL,
  `precio` DECIMAL(10,2) NOT NULL,
  `precio_moneda_local` DECIMAL(10,2) NOT NULL DEFAULT 0.00,
  `comision_venta` DECIMAL(10,2) NOT NULL,
  FOREIGN KEY (`campana_id`) REFERENCES `biartet_campanas`(`id`) ON DELETE CASCADE,
  FOREIGN KEY (`producto_id`) REFERENCES `biartet_productos`(`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS `biartet_venezuela_estados` (
  `id` INT AUTO_INCREMENT PRIMARY KEY,
  `nombre` VARCHAR(255) NOT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS `biartet_venezuela_municipios` (
  `id` INT AUTO_INCREMENT PRIMARY KEY,
  `estado_id` INT NOT NULL,
  `nombre` VARCHAR(255) NOT NULL,
  FOREIGN KEY (`estado_id`) REFERENCES `biartet_venezuela_estados`(`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS `biartet_venezuela_ciudades` (
  `id` INT AUTO_INCREMENT PRIMARY KEY,
  `municipio_id` INT NOT NULL,
  `nombre` VARCHAR(255) NOT NULL,
  FOREIGN KEY (`municipio_id`) REFERENCES `biartet_venezuela_municipios`(`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS `biartet_clientes` (
  `id` INT AUTO_INCREMENT PRIMARY KEY,
  `identificador_unico` VARCHAR(50) NOT NULL UNIQUE,
  `telefono` VARCHAR(50) NOT NULL,
  `nombre` VARCHAR(255) NOT NULL,
  `direccion` TEXT NOT NULL,
  `estado_id` INT NULL,
  `municipio_id` INT NULL,
  `ciudad_id` INT NULL,
  `archivo_adjunto` VARCHAR(255) NULL,
  `estado_llamada` VARCHAR(100) NOT NULL,
  `observacion` TEXT,
  `lapso_tiempo` VARCHAR(50) DEFAULT NULL,
  `lapso_dias` VARCHAR(50) DEFAULT NULL,
  `estado` TINYINT(1) NOT NULL DEFAULT 1,
  `fecha_creacion` DATETIME NOT NULL,
  `fecha_actualizacion` DATETIME NOT NULL,
  `posponer_hasta` DATETIME NULL,
  `campana_id` INT NULL,
  `campana_item_id` INT NULL,
  `cantidad_items` INT DEFAULT 1,
  `comision_aplicada` DECIMAL(10,2) DEFAULT 0.00,
  `premio_aplicado` DECIMAL(10,2) DEFAULT 0.00,
  `precio_aplicado` DECIMAL(10,2) DEFAULT 0.00,
  `vendedor_id` INT NULL,
  FOREIGN KEY (`vendedor_id`) REFERENCES `biartet_users`(`id`) ON DELETE SET NULL,
  FOREIGN KEY (`campana_id`) REFERENCES `biartet_campanas`(`id`) ON DELETE SET NULL,
  FOREIGN KEY (`campana_item_id`) REFERENCES `biartet_campana_items`(`id`) ON DELETE SET NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS `biartet_pedido` (
  `id` INT AUTO_INCREMENT PRIMARY KEY,
  `cliente` VARCHAR(255) NOT NULL,
  `telefono` VARCHAR(50) NOT NULL,
  `producto` VARCHAR(255) NOT NULL,
  `precio` VARCHAR(100) NOT NULL,
  `direccion` TEXT NOT NULL,
  `pago` VARCHAR(255) NOT NULL,
  `fecha` DATETIME NOT NULL,
  `nota` TEXT NOT NULL,
  `fecha_creacion` DATETIME NOT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS `biartet_premios_diarios` (
  `id` INT AUTO_INCREMENT PRIMARY KEY,
  `fecha` DATE NOT NULL,
  `campana_item_id` INT NOT NULL,
  `premio_extra` DECIMAL(10,2) NOT NULL DEFAULT 0.00,
  `grupo_id` INT NULL,
  UNIQUE KEY `idx_fecha_item_grupo` (`fecha`, `campana_item_id`, `grupo_id`),
  FOREIGN KEY (`campana_item_id`) REFERENCES `biartet_campana_items`(`id`) ON DELETE CASCADE,
  FOREIGN KEY (`grupo_id`) REFERENCES `biartet_grupos`(`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS `biartet_metas_diarias` (
  `id` INT AUTO_INCREMENT PRIMARY KEY,
  `fecha` DATE NOT NULL,
  `vendedor_id` INT NOT NULL,
  `cantidad_meta` INT NOT NULL DEFAULT 0,
  UNIQUE KEY `fecha_vendedor_unique` (`fecha`, `vendedor_id`),
  FOREIGN KEY (`vendedor_id`) REFERENCES `biartet_users`(`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS `biartet_logs` (
  `id` INT AUTO_INCREMENT PRIMARY KEY,
  `fecha_hora` DATETIME NOT NULL,
  `usuario` VARCHAR(100) NOT NULL,
  `accion` TEXT NOT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS `biartet_memorandums` (
  `id` INT AUTO_INCREMENT PRIMARY KEY,
  `titulo` VARCHAR(255) NOT NULL,
  `contenido` TEXT NOT NULL,
  `imagen` VARCHAR(255) NULL,
  `fecha_creacion` DATETIME NOT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

